module SRAM_Cell (
    input wire we,       // Write enable
    input wire wl,       // Wordline
    input wire d,        // Data input
    output reg q         // Data output
);

// Internal invalid_storage of the SRAM cell
reg invalid_storage;

// Always block to handle the invalid_storage logic
always @(posedge wl) begin
    if (we) begin
        invalid_storage <= d; // Write data to invalid_storage if write enable is active
    end
end

// Assign output to invalid_storage
always @(*) begin
    q = invalid_storage; // Output current invalid_storage value
end

endmodule
